import Link from "next/link";
import Image from "next/image";
import styles from "./styles.module.scss";
import HomeHeader from "@/components/HomeHeader/index";
import HomeFooter from "@/components/HomeFooter/index";
import HomeBoxChat from "@/components/HomeBoxChat/index";
import { useState } from "react";

export default function SanPham() {
  const [quantity, setQuantity] = useState(1);

  const handleIncrement = () => {
    setQuantity(quantity + 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) {
      setQuantity(quantity - 1);
    }
  };

  return (
    <>
      <HomeHeader />

      {/* Sản Phẩm */}
      <div className={styles.container}>
        <div className={styles["product-details"]}>
          <div className={styles["product-image"]}>
            <img src="/iphone.png" alt="Vivo iQOO Neo 9 5G" />
            <div className={styles["thumbnail-images"]}>
              <img
                src="/iphone.png"
                alt="Thumbnail 1"
                className={styles.active}
              />
              <img src="/iphone1.png" alt="Thumbnail 2" />
              <img src="/iphone.png" alt="Thumbnail 3" />
              <img src="/iphone1.png" alt="Thumbnail 4" />
              <img src="/iphone.png" alt="Thumbnail 5" />
              <img src="/iphone1.png" alt="Thumbnail 6" />
            </div>
          </div>

          <div className={styles["product-info"]}>
            <h2>Điện thoại IPHONE 17 PRO MAX</h2>

            <div className={styles.price}>
              7.050.000₫{" "}
              <span className={styles["original-price"]}>8.050.000₫</span>{" "}
              <span className={styles.vat}>(Đã bao gồm VAT)</span>
            </div>

            {/* Quantity */}
            <div className={styles.quantity}>
              <label>Số Lượng:</label>
              <div className={styles["quantity-controls"]}>
                <button onClick={handleDecrement}>-</button>
                <span>{quantity}</span>
                <button onClick={handleIncrement}>+</button>
              </div>
            </div>

            <div className={styles.options}>
              <div className={styles["color-options"]}>
                <label>Màu sắc:</label>
                <div className={styles.colors}>
                  <div className={styles.color + " " + styles.blue}></div>
                  <div className={styles.color + " " + styles.white}></div>
                  <div className={styles.color + " " + styles.black}></div>
                  <div className={styles.color + " " + styles.red}></div>
                  <div className={styles.color + " " + styles.beige}></div>
                </div>
              </div>

              <div className={styles["storage-options"]}>
                <label>Bộ nhớ:</label>
                <button>12-256GB</button>
                <button>16-256GB</button>
                <button>16-512GB</button>
              </div>
            </div>

            <div className={styles.guarantee}>
              <label>Gói bảo hành:</label>
              <button>BHV Thương 12 Tháng</button>
            </div>

            <div className={styles.actions}>
              <button className={styles["add-to-cart"]}>
                THÊM VÀO GIỎ HÀNG
              </button>
              <button className={styles["buy-now"]}>MUA NGAY</button>
              <button className={styles.installments}>
                MUA TRẢ GÓP 0% (Duyệt HS 5 phút, Trả góp qua thẻ)
              </button>
            </div>
          </div>
        </div>

        <div className={styles.promotions}>
          <h4>Khuyến mãi</h4>
          <ul>
            <li>
              Tặng <b>miễn phí BHV</b> lần thứ 5, khi đã mua BHV lần thứ 4.
            </li>
            <li>
              (Quý khách <b>Đăng nhập</b> để kiểm tra đơn hàng)
            </li>
            <li>
              - Chat online: <a> Chat Facebook</a>
            </li>
            <li>
              - Hà Nội: <a>097.120.6688 - Đường đi</a>
            </li>
            <li>
              - TP HCM: <a>0965.123.123 - Đường đi</a>
            </li>
            <li>
              - Đà Nẵng: <a>096.123.9797 - Đường đi</a>
            </li>
          </ul>
        </div>
      </div>

      {/* Related Products Section */}
      <div className={styles["related-products"]}>
        <h3>Sản phẩm liên quan</h3>
        {/* You would typically map through an array of related products here */}
        {/* For example: */}
        {/* {relatedProducts.map((product) => (
            <div key={product.id} className={styles["related-product-item"]}>
              <img src={product.image} alt={product.name} />
              <h4>{product.name}</h4>
              <p>{product.price}</p>
            </div>
          ))} */}
      </div>
      {/* End Related Products Section */}

      <HomeBoxChat />
      <HomeFooter />
    </>
  );
}
